SELECT creators.creator_name, repositories.repository_name
FROM creators
JOIN repositories ON creators.creator_id = repositories.repository_id;

SELECT p.project_id, p.project_name
FROM projects AS p
INNER JOIN user_projects AS up ON p.project_id = up.project_id;

SELECT AVG(collaborator_count) AS average_collaborators_per_project
FROM (
    SELECT project_id, COUNT(user_id) AS collaborator_count
    FROM collaborations
    GROUP BY project_id
) AS project_collaborators;

SELECT 
    (SELECT COUNT(*) FROM users) AS number_of_users,
    (SELECT COUNT(*) FROM projects) AS number_of_projects;

SELECT COUNT(*) 
FROM user_projects 
WHERE project_id = 'abc123';

SELECT users.user_id
FROM users
JOIN user_projects ON users.user_id = user_projects.user_id
WHERE user_projects.project_id = (
    SELECT project_id FROM projects WHERE project_name = 'Project Name'
);

SELECT AVG(user_count) AS average_users_per_project
FROM (
  SELECT COUNT(user_id) AS user_count
  FROM user_projects
  GROUP BY project_id
) AS project_users;
